// Simple mode: quick reply without RAG/detection. Use when frontend sends workflow: 'simple' or model_tier: 'light'.
const raw = $input.first().json.body || $input.first().json || {};
const session_id = raw.session_id || '';
const request_id = raw.request_id || '';
const msg = (raw.message || '').trim() || 'Hello';
return [{ json: {
  session_id,
  request_id,
  coaching_mode: 'emotional_support',
  message: { content: `I'm here to help. (Quick mode — for detailed policy or coaching, switch to Standard or Detailed.) You said: "${msg.slice(0, 80)}${msg.length > 80 ? '…' : ''}"` }
}}];
